     1→     1→<!DOCTYPE html>
     2→     2→<html lang="en">
     3→     3→<head>
     4→     4→<meta charset="UTF-8"/>
     5→     5→<meta name="viewport" content="width=device-width, initial-scale=1.0"/>
     6→     6→<title>GymBuddy</title>
     7→     7→<style>
     8→     8→*{box-sizing:border-box;margin:0;padding:0}
     9→     9→body{background:#0a0a0f;color:#e2e8f0;font-family:'JetBrains Mono','SF Mono','Fira Code',monospace;min-height:100vh}
    10→    10→input[type=number]::-webkit-outer-spin-button,
    11→    11→input[type=number]::-webkit-inner-spin-button{-webkit-appearance:none}
    12→    12→input[type=number]{-moz-appearance:textfield}
    13→    13→
    14→    14→/* ── ONBOARDING ─────────────────────────────────────────────────────── */
    15→    15→#onboarding{display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:100vh;padding:24px}
    16→    16→.ob-wrap{width:100%;max-width:420px}
    17→    17→.ob-logo{font-size:26px;font-weight:800;letter-spacing:5px;color:#f97316;margin-bottom:4px}
    18→    18→.ob-tagline{font-size:11px;color:#64748b;letter-spacing:2px;margin-bottom:32px}
    19→    19→.ob-step{display:none}
    20→    20→.ob-step.active{display:block}
    21→    21→.ob-progress{display:flex;gap:6px;margin-bottom:28px}
    22→    22→.ob-dot{flex:1;height:3px;border-radius:2px;background:#1e293b;transition:background .3s}
    23→    23→.ob-dot.done{background:#f97316}
    24→    24→.ob-title{font-size:20px;font-weight:700;color:#e2e8f0;margin-bottom:6px}
    25→    25→.ob-sub{font-size:12px;color:#64748b;margin-bottom:24px}
    26→    26→.ob-input{width:100%;padding:12px 14px;background:#111118;border:1px solid #1e293b;border-radius:10px;color:#e2e8f0;font-size:15px;font-family:inherit;outline:none;margin-bottom:12px;transition:border .15s}
    27→    27→.ob-input:focus{border-color:#f97316}
    28→    28→.ob-input::placeholder{color:#334155}
    29→    29→.ob-row{display:flex;gap:10px;margin-bottom:12px}
    30→    30→.ob-row .ob-input{margin-bottom:0}
    31→    31→.chip-group{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:16px}
    32→    32→.chip{padding:10px 16px;background:#111118;border:1px solid #1e293b;border-radius:8px;color:#64748b;font-size:12px;font-family:inherit;cursor:pointer;transition:all .15s;text-align:left;flex:1;min-width:80px}
    33→    33→.chip:hover{border-color:#f97316;color:#e2e8f0}
    34→    34→.chip.selected{background:rgba(249,115,22,0.12);border-color:#f97316;color:#f97316;font-weight:700}
    35→    35→.chip-icon{display:block;font-size:20px;margin-bottom:4px}
    36→    36→.chip-desc{font-size:10px;color:#64748b;margin-top:2px;display:block}
    37→    37→.day-btn-group{display:flex;gap:6px;margin-bottom:16px}
    38→    38→.day-btn{flex:1;padding:14px 0;background:#111118;border:1px solid #1e293b;border-radius:8px;color:#64748b;font-size:18px;font-weight:800;font-family:inherit;cursor:pointer;transition:all .15s}
    39→    39→.day-btn.selected{background:rgba(249,115,22,0.12);border-color:#f97316;color:#f97316}
    40→    40→.ob-btn{width:100%;padding:14px 0;background:#f97316;border:none;border-radius:10px;color:#0a0a0f;font-weight:800;font-size:14px;font-family:inherit;cursor:pointer;letter-spacing:1px;margin-top:8px}
    41→    41→.ob-btn:hover{background:#fb923c}
    42→    42→.ob-btn-ghost{width:100%;padding:12px 0;background:transparent;border:1px solid #1e293b;border-radius:10px;color:#64748b;font-size:12px;font-family:inherit;cursor:pointer;margin-top:8px}
    43→    43→.ob-review{background:#111118;border:1px solid #1e293b;border-radius:12px;padding:20px;margin-bottom:20px}
    44→    44→.ob-review-row{display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid rgba(30,41,59,0.6);font-size:13px}
    45→    45→.ob-review-row:last-child{border:none}
    46→    46→.ob-review-key{color:#64748b}
    47→    47→.ob-review-val{color:#f97316;font-weight:700}
    48→    48→.ob-plan-preview{background:#0a0a0f;border:1px solid #1e293b;border-radius:8px;padding:12px;margin-top:12px}
    49→    49→.ob-plan-day{font-size:12px;padding:4px 0;color:#94a3b8;border-bottom:1px solid rgba(30,41,59,0.4)}
    50→    50→.ob-plan-day:last-child{border:none}
    51→    51→.ob-plan-day strong{color:#f97316}
    52→    52→
    53→    53→/* ── MAIN APP ───────────────────────────────────────────────────────── */
    54→    54→#app{display:none;max-width:480px;margin:0 auto;padding:0 16px 80px}
    55→    55→.header{display:flex;justify-content:space-between;align-items:center;padding:24px 0 16px;border-bottom:1px solid #1e293b}
    56→    56→.header-left{}
    57→    57→.app-name{font-size:11px;color:#f97316;font-weight:700;letter-spacing:3px;text-transform:uppercase}
    58→    58→.app-greeting{font-size:18px;font-weight:800;color:#e2e8f0;letter-spacing:1px}
    59→    59→.app-goal{font-size:10px;color:#64748b;margin-top:2px;letter-spacing:1px}
    60→    60→.streak-badge{display:flex;flex-direction:column;align-items:center;background:#1a1a2e;border-radius:10px;padding:8px 14px;border:1px solid rgba(249,115,22,0.19)}
    61→    61→.streak-num{font-size:24px;font-weight:800;color:#f97316}
    62→    62→.streak-label{font-size:9px;color:#64748b;text-transform:uppercase;letter-spacing:1px}
    63→    63→.tabs{display:flex;gap:4px;padding:12px 0;border-bottom:1px solid #1e293b}
    64→    64→.tab{flex:1;padding:8px 0;background:transparent;border:1px solid #1e293b;border-radius:6px;color:#64748b;font-size:11px;font-family:inherit;cursor:pointer;transition:all .15s}
    65→    65→.tab.active{background:#f97316;color:#0a0a0f;border-color:#f97316;font-weight:700}
    66→    66→.panel{display:none;padding-top:16px}
    67→    67→.panel.active{display:block}
    68→    68→.section{margin-bottom:24px}
    69→    69→.section-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:8px}
    70→    70→.section-title{font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:2px;color:#94a3b8;margin-bottom:12px}
    71→    71→
    72→    72→/* Habits */
    73→    73→.habit-count{font-size:13px;font-weight:700;color:#f97316}
    74→    74→.habit-bar{height:4px;background:#1e293b;border-radius:2px;margin-bottom:12px;overflow:hidden}
    75→    75→.habit-bar-fill{height:100%;background:linear-gradient(90deg,#f97316,#fb923c);border-radius:2px;transition:width .3s ease;width:0%}
    76→    76→.habit-row{display:flex;align-items:center;width:100%;padding:10px 12px;background:#111118;border:1px solid #1e293b;border-radius:8px;margin-bottom:6px;cursor:pointer;font-family:inherit;color:#e2e8f0;font-size:13px;text-align:left;transition:all .15s}
    77→    77→.habit-row.done{border-color:rgba(249,115,22,0.25);background:rgba(249,115,22,0.06)}
    78→    78→.habit-row.done .habit-label{text-decoration:line-through;opacity:.5}
    79→    79→.habit-icon{margin-right:10px;font-size:16px}
    80→    80→.habit-label{flex:1}
    81→    81→.habit-check{color:#f97316;font-weight:700;font-size:16px}
    82→    82→
    83→    83→/* Workout start */
    84→    84→.workout-btns{display:flex;gap:8px}
    85→    85→.workout-type-btn{flex:1;display:flex;flex-direction:column;align-items:center;padding:14px 6px;background:#111118;border:1px solid #1e293b;border-radius:10px;cursor:pointer;font-family:inherit;color:#e2e8f0;transition:all .15s}
    86→    86→.workout-type-btn:hover{border-color:#f97316}
    87→    87→.workout-type-letter{font-size:22px;font-weight:800;color:#f97316}
    88→    88→.workout-type-name{font-size:9px;color:#64748b;text-transform:uppercase;letter-spacing:1px;margin-top:2px;text-align:center}
    89→    89→.workout-last{font-size:9px;color:#334155;margin-top:3px;text-align:center}
    90→    90→
    91→    91→/* Body inputs */
    92→    92→.body-input-row{display:flex;gap:8px}
    93→    93→input.ob-input,input.set-input,input.body-input{background:#111118;border:1px solid #1e293b;border-radius:8px;color:#e2e8f0;font-family:inherit;outline:none;transition:border .15s}
    94→    94→input.body-input{flex:1;padding:10px 12px;font-size:14px}
    95→    95→input.body-input:focus{border-color:#f97316}
    96→    96→.log-btn{padding:10px 20px;background:#f97316;border:none;border-radius:8px;color:#0a0a0f;font-weight:700;font-size:13px;font-family:inherit;cursor:pointer}
    97→    97→
    98→    98→/* Workout session */
    99→    99→#workout-screen{display:none;max-width:480px;margin:0 auto;padding:0 16px 48px}
   100→   100→.workout-header{display:flex;align-items:center;gap:12px;padding:20px 0 16px;border-bottom:1px solid #1e293b}
   101→   101→.back-btn{padding:6px 12px;background:#1e293b;border:none;border-radius:6px;color:#94a3b8;font-family:inherit;font-size:12px;cursor:pointer}
   102→   102→.workout-session-title{font-size:18px;font-weight:800;color:#f97316;letter-spacing:2px}
   103→   103→.exercise-card{background:#111118;border:1px solid #1e293b;border-radius:10px;padding:16px;margin-bottom:10px;margin-top:10px}
   104→   104→.exercise-name{font-size:14px;font-weight:700;color:#e2e8f0;margin-bottom:4px}
   105→   105→.target-text{font-size:11px;color:#64748b;margin-bottom:10px}
   106→   106→.sets-grid{display:flex;flex-direction:column;gap:6px}
   107→   107→.set-row{display:flex;align-items:center;gap:8px}
   108→   108→.set-label{font-size:11px;color:#64748b;width:40px;flex-shrink:0}
   109→   109→input.set-input{flex:1;padding:7px 10px;font-size:13px;max-width:80px;border-radius:6px}
   110→   110→input.set-input:focus{border-color:#f97316}
   111→   111→.finish-btn{width:100%;padding:14px 0;background:#f97316;border:none;border-radius:10px;color:#0a0a0f;font-weight:800;font-size:15px;font-family:inherit;cursor:pointer;margin-top:16px;letter-spacing:1px}
   112→   112→
   113→   113→/* Log tab */
   114→   114→.workout-log-card{background:#111118;border:1px solid #1e293b;border-radius:10px;padding:14px;margin-bottom:8px}
   115→   115→.log-card-header{display:flex;justify-content:space-between;margin-bottom:10px}
   116→   116→.log-card-type{font-weight:700;color:#f97316;font-size:13px}
   117→   117→.log-card-date{color:#64748b;font-size:11px}
   118→   118→.log-exercise{display:flex;justify-content:space-between;align-items:center;padding:4px 0;border-top:1px solid rgba(30,41,59,0.3)}
   119→   119→.log-ex-name{font-size:12px;color:#94a3b8}
   120→   120→.log-ex-sets{font-size:11px;color:#64748b}
   121→   121→.empty-text{color:#475569;font-size:13px;text-align:center;padding:32px}
   122→   122→
   123→   123→/* AI Paste tab */
   124→   124→.paste-area{width:100%;min-height:160px;padding:14px;background:#111118;border:1px solid #1e293b;border-radius:10px;color:#e2e8f0;font-size:13px;font-family:inherit;outline:none;resize:vertical;line-height:1.6}
   125→   125→.paste-area:focus{border-color:#f97316}
   126→   126→.paste-area::placeholder{color:#334155}
   127→   127→.parse-btn{width:100%;padding:12px 0;background:#f97316;border:none;border-radius:8px;color:#0a0a0f;font-weight:700;font-size:13px;font-family:inherit;cursor:pointer;margin-top:10px;letter-spacing:1px}
   128→   128→.parse-hint{font-size:11px;color:#475569;margin-top:10px;line-height:1.7}
   129→   129→.parse-hint code{color:#64748b;background:#111118;padding:1px 5px;border-radius:4px}
   130→   130→.parse-preview{background:#111118;border:1px solid #1e293b;border-radius:10px;padding:16px;margin-top:16px;display:none}
   131→   131→.parse-preview-title{font-size:12px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:2px;margin-bottom:12px}
   132→   132→.parse-row{display:flex;justify-content:space-between;font-size:12px;padding:5px 0;border-bottom:1px solid rgba(30,41,59,0.4)}
   133→   133→.parse-row:last-child{border:none}
   134→   134→.parse-key{color:#64748b}
   135→   135→.parse-val{color:#e2e8f0;font-weight:600;text-align:right;max-width:60%}
   136→   136→.parse-confirm{width:100%;padding:12px 0;background:#10b981;border:none;border-radius:8px;color:#fff;font-weight:700;font-size:13px;font-family:inherit;cursor:pointer;margin-top:12px}
   137→   137→.parse-discard{width:100%;padding:10px 0;background:transparent;border:1px solid rgba(239,68,68,0.3);border-radius:8px;color:#ef4444;font-size:11px;font-family:inherit;cursor:pointer;margin-top:6px}
   138→   138→.badge{display:inline-block;padding:2px 8px;border-radius:20px;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:1px}
   139→   139→.badge-green{background:rgba(16,185,129,0.15);color:#10b981;border:1px solid rgba(16,185,129,0.3)}
   140→   140→.badge-orange{background:rgba(249,115,22,0.15);color:#f97316;border:1px solid rgba(249,115,22,0.3)}
   141→   141→.badge-gray{background:rgba(100,116,139,0.15);color:#64748b;border:1px solid rgba(100,116,139,0.3)}
   142→   142→
   143→   143→/* Progress tab */
   144→   144→.progress-bar{height:8px;background:#1e293b;border-radius:4px;overflow:hidden;margin-bottom:8px}
   145→   145→.progress-bar-fill{height:100%;background:linear-gradient(90deg,#f97316,#fbbf24);border-radius:4px;transition:width .5s ease}
   146→   146→.progress-labels{display:flex;justify-content:space-between;font-size:10px;color:#64748b}
   147→   147→.current-weight-label{color:#f97316;font-weight:700}
   148→   148→.body-log-header{display:grid;grid-template-columns:1fr 1fr 1fr;padding:6px 0;font-size:10px;color:#475569;text-transform:uppercase;letter-spacing:1px;border-bottom:1px solid #1e293b}
   149→   149→.body-log-row{display:grid;grid-template-columns:1fr 1fr 1fr;padding:8px 0;font-size:12px;border-bottom:1px solid rgba(30,41,59,0.3)}
   150→   150→.body-log-date{color:#64748b}
   151→   151→.body-log-val{color:#e2e8f0;font-weight:600}
   152→   152→.stats-grid{display:flex;gap:8px}
   153→   153→.stat-card{flex:1;display:flex;flex-direction:column;align-items:center;padding:14px 8px;background:#111118;border:1px solid #1e293b;border-radius:10px}
   154→   154→.stat-num{font-size:26px;font-weight:800;color:#f97316}
   155→   155→.stat-label{font-size:9px;color:#64748b;text-transform:uppercase;letter-spacing:1px;margin-top:4px;text-align:center}
   156→   156→.reset-btn{width:100%;padding:10px 0;background:transparent;border:1px solid rgba(239,68,68,0.25);border-radius:8px;color:#ef4444;font-size:11px;font-family:inherit;cursor:pointer;margin-top:24px}
   157→   157→
   158→   158→/* Saved toast */
   159→   159→.toast{position:fixed;bottom:20px;left:50%;transform:translateX(-50%) translateY(80px);padding:10px 20px;background:#10b981;color:#fff;border-radius:8px;font-size:12px;font-weight:700;transition:transform .3s ease;z-index:100;pointer-events:none}
   160→   160→.toast.show{transform:translateX(-50%) translateY(0)}
   161→   161→</style>
   162→   162→</head>
   163→   163→<body>
   164→   164→
   165→   165→<!-- ── ONBOARDING ──────────────────────────────────────────────────────── -->
   166→   166→<div id="onboarding">
   167→   167→  <div class="ob-wrap">
   168→   168→    <div class="ob-logo">GYMBUDDY</div>
   169→   169→    <div class="ob-tagline">YOUR AI TRAINING PARTNER</div>
   170→   170→    <div class="ob-progress" id="ob-progress"></div>
   171→   171→
   172→   172→    <!-- Step 1: Name -->
   173→   173→    <div class="ob-step active" id="step-1">
   174→   174→      <div class="ob-title">Welcome 👋</div>
   175→   175→      <div class="ob-sub">Let's build your personalised program.</div>
   176→   176→      <input class="ob-input" id="ob-name" type="text" placeholder="What's your name?" autocomplete="off"/>
   177→   177→      <button class="ob-btn" onclick="nextStep(1)">Get Started →</button>
   178→   178→    </div>
   179→   179→
   180→   180→    <!-- Step 2: Body stats -->
   181→   181→    <div class="ob-step" id="step-2">
   182→   182→      <div class="ob-title">About you</div>
   183→   183→      <div class="ob-sub">Used to calculate your calorie & protein targets.</div>
   184→   184→      <div class="chip-group" id="sex-group">
   185→   185→        <button class="chip" onclick="selectChip('sex-group',this,'male')">♂ Male</button>
   186→   186→        <button class="chip" onclick="selectChip('sex-group',this,'female')">♀ Female</button>
   187→   187→        <button class="chip" onclick="selectChip('sex-group',this,'other')">Other</button>
   188→   188→      </div>
   189→   189→      <div class="ob-row">
   190→   190→        <input class="ob-input" id="ob-height" type="number" placeholder="Height (cm)" min="140" max="220"/>
   191→   191→        <input class="ob-input" id="ob-weight" type="number" placeholder="Weight (kg)" min="40" max="200" step="0.1"/>
   192→   192→      </div>
   193→   193→      <input class="ob-input" id="ob-bf" type="number" placeholder="Body fat % (optional)" min="5" max="50" step="0.5"/>
   194→   194→      <button class="ob-btn" onclick="nextStep(2)">Continue →</button>
   195→   195→      <button class="ob-btn-ghost" onclick="prevStep(2)">← Back</button>
   196→   196→    </div>
   197→   197→
   198→   198→    <!-- Step 3: Goal -->
   199→   199→    <div class="ob-step" id="step-3">
   200→   200→      <div class="ob-title">What's your goal?</div>
   201→   201→      <div class="ob-sub">This shapes your nutrition targets and plan intensity.</div>
   202→   202→      <div class="chip-group" id="goal-group" style="flex-direction:column">
   203→   203→        <button class="chip" onclick="selectChip('goal-group',this,'bulk')" style="min-width:100%">
   204→   204→          <span class="chip-icon">💪</span>Bulk — Build Muscle
   205→   205→          <span class="chip-desc">Calorie surplus · prioritise strength gains</span>
   206→   206→        </button>
   207→   207→        <button class="chip" onclick="selectChip('goal-group',this,'cut')" style="min-width:100%">
   208→   208→          <span class="chip-icon">🔥</span>Cut — Lose Fat
   209→   209→          <span class="chip-desc">Calorie deficit · preserve muscle mass</span>
   210→   210→        </button>
   211→   211→        <button class="chip" onclick="selectChip('goal-group',this,'recomp')" style="min-width:100%">
   212→   212→          <span class="chip-icon">⚖️</span>Recomp — Both
   213→   213→          <span class="chip-desc">Maintenance calories · body composition shift</span>
   214→   214→        </button>
   215→   215→        <button class="chip" onclick="selectChip('goal-group',this,'maintain')" style="min-width:100%">
   216→   216→          <span class="chip-icon">🎯</span>Maintain — Stay Consistent
   217→   217→          <span class="chip-desc">Healthy habits · keep current physique</span>
   218→   218→        </button>
   219→   219→      </div>
   220→   220→      <button class="ob-btn" onclick="nextStep(3)">Continue →</button>
   221→   221→      <button class="ob-btn-ghost" onclick="prevStep(3)">← Back</button>
   222→   222→    </div>
   223→   223→
   224→   224→    <!-- Step 4: Experience -->
   225→   225→    <div class="ob-step" id="step-4">
   226→   226→      <div class="ob-title">Training experience</div>
   227→   227→      <div class="ob-sub">Helps us set the right volume and intensity.</div>
   228→   228→      <div class="chip-group" id="exp-group" style="flex-direction:column">
   229→   229→        <button class="chip" onclick="selectChip('exp-group',this,'beginner')" style="min-width:100%">
   230→   230→          <span class="chip-icon">🌱</span>Beginner — Under 1 year
   231→   231→          <span class="chip-desc">Learning the lifts · building base strength</span>
   232→   232→        </button>
   233→   233→        <button class="chip" onclick="selectChip('exp-group',this,'intermediate')" style="min-width:100%">
   234→   234→          <span class="chip-icon">🏋️</span>Intermediate — 1–3 years
   235→   235→          <span class="chip-desc">Solid form · ready for progressive overload</span>
   236→   236→        </button>
   237→   237→        <button class="chip" onclick="selectChip('exp-group',this,'advanced')" style="min-width:100%">
   238→   238→          <span class="chip-icon">🔱</span>Advanced — 3+ years
   239→   239→          <span class="chip-desc">High volume · auto-regulation · specialisation</span>
   240→   240→        </button>
   241→   241→      </div>
   242→   242→      <button class="ob-btn" onclick="nextStep(4)">Continue →</button>
   243→   243→      <button class="ob-btn-ghost" onclick="prevStep(4)">← Back</button>
   244→   244→    </div>
   245→   245→
   246→   246→    <!-- Step 5: Days/week -->
