   781→   781→function buildReview() {
   782→   782→  const targets = calcTargets();
   783→   783→  const planData = generatePlan();
   784→   784→  const goalLabels={bulk:'Bulk — Build Muscle',cut:'Cut — Lose Fat',recomp:'Recomp',maintain:'Maintain'};
   785→   785→  const expLabels={beginner:'Beginner',intermediate:'Intermediate',advanced:'Advanced'};
   786→   786→  document.getElementById('ob-review-content').innerHTML=`
   787→   787→    <div class="ob-review-row"><span class="ob-review-key">Name</span><span class="ob-review-val">${ob.name}</span></div>
   788→   788→    <div class="ob-review-row"><span class="ob-review-key">Stats</span><span class="ob-review-val">${ob.weight}kg · ${ob.height}cm${ob.bf?' · '+ob.bf+'% BF':''}</span></div>
   789→   789→    <div class="ob-review-row"><span class="ob-review-key">Goal</span><span class="ob-review-val">${goalLabels[ob.goal]}</span></div>
   790→   790→    <div class="ob-review-row"><span class="ob-review-key">Level</span><span class="ob-review-val">${expLabels[ob.experience]}</span></div>
   791→   791→    <div class="ob-review-row"><span class="ob-review-key">Training</span><span class="ob-review-val">${ob.days} days/week</span></div>
   792→   792→    <div class="ob-review-row"><span class="ob-review-key">Calories</span><span class="ob-review-val">${targets.calories} kcal/day</span></div>
   793→   793→    <div class="ob-review-row"><span class="ob-review-key">Protein</span><span class="ob-review-val">${targets.protein}g/day</span></div>
   794→   794→    <div class="ob-review-row"><span class="ob-review-key">Split</span><span class="ob-review-val">${PLANS[ob.days].label}</span></div>
   795→   795→    <div class="ob-plan-preview">${planData.workouts.map(w=>`<div class="ob-plan-day"><strong>${w.key}</strong> — ${w.name} (${w.focus})</div>`).join('')}</div>
   796→   796→  `;
   797→   797→}
