   799→   799→function calcTargets() {
   800→   800→  const w=parseFloat(ob.weight)||70, h=parseFloat(ob.height)||170;
   801→   801→  const bmr = ob.sex==='female' ? 10*w+6.25*h-5*25-161 : 10*w+6.25*h-5*25+5;
   802→   802→  const tdee = Math.round(bmr*1.55);
   803→   803→  let calories, protein;
   804→   804→  if(ob.goal==='bulk')     { calories=tdee+300; protein=Math.round(w*2.0); }
   805→   805→  else if(ob.goal==='cut') { calories=tdee-400; protein=Math.round(w*2.2); }
   806→   806→  else                     { calories=tdee;     protein=Math.round(w*1.8); }
   807→   807→  return { calories: Math.round(calories/50)*50, protein };
   808→   808→}
   809→   809→
   810→   810→function generatePlan() {
   811→   811→  const template = PLANS[ob.days];
   812→   812→  const exp = ob.experience || 'intermediate';
   813→   813→  const workouts = template.workouts.map(w=>({
   814→   814→    key: w.key,
   815→   815→    name: w.name,
   816→   816→    focus: w.focus,
   817→   817→    exercises: (w[exp]||w.intermediate).map(e=>({...e})),
   818→   818→  }));
   819→   819→  return { workouts, splitLabel: template.label };
   820→   820→}
