   898→   898→function renderStreak() {
   899→   899→  const HABITS=getHabits();
   900→   900→  let count=0;
   901→   901→  const d=new Date();
   902→   902→  for(let i=0;i<365;i++){
   903→   903→    const key=d.toISOString().slice(0,10);
   904→   904→    const dayH=habits[key]||{};
   905→   905→    const done=HABITS.filter(h=>dayH[h.id]).length;
   906→   906→    if(done<3&&count>0) break;
   907→   907→    if(done<3&&count===0){d.setDate(d.getDate()-1);continue;}
   908→   908→    count++;
   909→   909→    d.setDate(d.getDate()-1);
   910→   910→  }
   911→   911→  document.getElementById('streak-num').textContent=count;
   912→   912→}
