  1027→  1027→    aliases[ex.name]=[nm,...words, words.join('')];
  1028→  1028→    // common shorthands
  1029→  1029→    if(nm.includes('squat')) aliases[ex.name].push('squat','squats');
  1030→  1030→    if(nm.includes('bench')) aliases[ex.name].push('bench','bp');
  1031→  1031→    if(nm.includes('row')) aliases[ex.name].push('row','rows');
