  1035→  1035→    if(nm.includes('pulldown')) aliases[ex.name].push('pulldown','lat pull');
  1036→  1036→    if(nm.includes('curl')) aliases[ex.name].push('curl','curls');
  1037→  1037→    if(nm.includes('dip')) aliases[ex.name].push('dip','dips');
  1038→  1038→    if(nm.includes('plank')) aliases[ex.name].push('plank');
