  1041→  1041→    if(nm.includes('pull-up')||nm.includes('pullup')) aliases[ex.name].push('pullup','pullups','pull up','pull-up','chinup','chin up');
  1042→  1042→    if(nm.includes('hip thrust')) aliases[ex.name].push('hip thrust','hip thrusts','glute bridge');
  1043→  1043→    if(nm.includes('leg press')) aliases[ex.name].push('leg press');
  1044→  1044→    if(nm.includes('leg curl')) aliases[ex.name].push('leg curl','hamstring curl');
  1045→  1045→    if(nm.includes('calf')) aliases[ex.name].push('calf','calves','calf raise');
  1046→  1046→    if(nm.includes('face pull')) aliases[ex.name].push('face pull','face pulls');
