  1056→  1056→function matchExercise(text, aliases) {
  1057→  1057→  const t=text.toLowerCase().replace(/[^a-z0-9\s]/g,'').trim();
  1058→  1058→  for(const [name, patterns] of Object.entries(aliases)){
  1059→  1059→    if(patterns.some(p=>t.includes(p.toLowerCase()))) return name;
  1060→  1060→  }
  1061→  1061→  return null;
  1062→  1062→}
