  1064→  1064→function parseSets(text) {
  1065→  1065→  // Patterns: "80kg x8 x7 x8", "3x10 @70kg", "70 8 8 8", "80/82/85 x6"
  1066→  1066→  const sets=[];
  1067→  1067→  // pattern: weight×reps pairs like "80kg x8" repeated
  1068→  1068→  const pairPattern=/(\d+(?:\.\d+)?)\s*(?:kg)?\s*[x×]\s*(\d+)/gi;
  1069→  1069→  let m;
  1070→  1070→  while((m=pairPattern.exec(text))!==null){
  1071→  1071→    sets.push({weight:m[1],reps:m[2]});
  1072→  1072→  }
  1073→  1073→  if(sets.length) return sets;
  1074→  1074→  // pattern: "3x10 @70" or "3x10 70kg"
  1075→  1075→  const setsRepsWeight=/(\d+)\s*[x×]\s*(\d+)\s*@?\s*(\d+(?:\.\d+)?)/i.exec(text);
  1076→  1076→  if(setsRepsWeight){
  1077→  1077→    const n=parseInt(setsRepsWeight[1]);
  1078→  1078→    for(let i=0;i<n;i++) sets.push({weight:setsRepsWeight[3],reps:setsRepsWeight[2]});
  1079→  1079→    return sets;
  1080→  1080→  }
  1081→  1081→  // pattern: "weight x reps x reps" like "80 x 8 8 7"
  1082→  1082→  const wFirst=/(\d+(?:\.\d+)?)\s*(?:kg)?\s*[x×]\s*([\d\s]+)/i.exec(text);
  1083→  1083→  if(wFirst){
  1084→  1084→    const reps=wFirst[2].trim().split(/\s+/);
  1085→  1085→    reps.forEach(r=>{ if(/^\d+$/.test(r)) sets.push({weight:wFirst[1],reps:r}); });
  1086→  1086→    if(sets.length) return sets;
  1087→  1087→  }
  1088→  1088→  return [];
  1089→  1089→}
