  1133→  1133→
  1134→  1134→    // Weight / BF
  1135→  1135→    const weightM=line.match(/(?:weight|bw|weighed?)[:\s]+(\d+(?:\.\d+)?)\s*(?:kg)?/i);
  1136→  1136→    if(weightM){result.weight=parseFloat(weightM[1]);continue;}
